var CONVERSATIONS_HI_SQ = [
{ title: "तिराना के कैफ़े में कॉफ़ी ऑर्डर करना", scene: "आप तिराना के ब्लोकू इलाके के एक कैफ़े में हैं। आप कॉफ़ी, पानी और ब्यूरेक ऑर्डर करना चाहते हैं। बातचीत विनम्र और तेज़ है, जैसे व्यस्त कैफ़े में होती है।", lines: [{ who: "them", sq: "Përshëndetje, çfarë dëshironi?", hi: "नमस्ते, आप क्या चाहेंगे?" }, { who: "you", sq: "Përshëndetje, dua një kafe, ju lutem.", hi: "नमस्ते, मुझे एक कॉफ़ी चाहिए, कृपया।" }, { who: "them", sq: "Me sheqer apo pa sheqer?", hi: "चीनी के साथ या बिना चीनी?" }, { who: "you", sq: "Pa sheqer, ju lutem.", hi: "बिना चीनी, कृपया।" }, { who: "them", sq: "Dëshironi edhe ujë?", hi: "क्या आप पानी भी चाहेंगे?" }, { who: "you", sq: "Po, një ujë të ftohtë.", hi: "हाँ, एक ठंडा पानी।" }, { who: "them", sq: "A doni byrek?", hi: "क्या आप ब्यूरेक चाहेंगे?" }, { who: "you", sq: "Po, a keni byrek me djathë?", hi: "हाँ, क्या आपके पास चीज़ वाला ब्यूरेक है?" }, { who: "them", sq: "Po, kemi.", hi: "हाँ, हमारे पास है।" }, { who: "you", sq: "Shumë mirë, do ta marr.", hi: "बहुत अच्छा, मैं इसे ले लूँगा/लूँगी।" }, { who: "them", sq: "Pagesa tani apo më vonë?", hi: "भुगतान अभी या बाद में?" }, { who: "you", sq: "Tani, me kartë, ju lutem.", hi: "अभी, कार्ड से, कृपया।" }] },
{ title: "होटल में चेक-इन", scene: "आप व्लोरा के एक समुद्र-तट वाले होटल में पहुँचते हैं। आपकी पहले से बुकिंग है और आप नाश्ते तथा चेक-आउट समय के बारे में पूछते हैं।", lines: [{ who: "them", sq: "Mirëmbrëma, mirë se vini në hotel.", hi: "शुभ संध्या, होटल में आपका स्वागत है।" }, { who: "you", sq: "Mirëmbrëma, kam një rezervim.", hi: "शुभ संध्या, मेरी एक बुकिंग है।" }, { who: "them", sq: "Në çfarë emri është rezervimi?", hi: "बुकिंग किस नाम से है?" }, { who: "you", sq: "Emri im është Ravi Sharma.", hi: "मेरा नाम रवि शर्मा है।" }, { who: "them", sq: "Mund të shoh pasaportën?", hi: "क्या मैं पासपोर्ट देख सकता/सकती हूँ?" }, { who: "you", sq: "Po, ja pasaporta ime.", hi: "हाँ, यह मेरा पासपोर्ट है।" }, { who: "them", sq: "Dhoma juaj është në katin e dytë.", hi: "आपका कमरा दूसरी मंज़िल पर है।" }, { who: "you", sq: "Faleminderit, a përfshihet mëngjesi?", hi: "धन्यवाद, क्या नाश्ता शामिल है?" }, { who: "them", sq: "Po, mëngjesi është nga ora shtatë deri në dhjetë.", hi: "हाँ, नाश्ता सात से दस बजे तक है।" }, { who: "you", sq: "Shumë mirë, në çfarë ore është dalja?", hi: "बहुत अच्छा, चेक-आउट किस समय है?" }, { who: "them", sq: "Dalja është në orën njëmbëdhjetë.", hi: "चेक-आउट ग्यारह बजे है।" }, { who: "you", sq: "Faleminderit shumë.", hi: "बहुत धन्यवाद।" }] },
{ title: "रास्ता पूछना", scene: "आप श्कोद्रा में पुराने शहर के पास हैं और बस स्टेशन ढूँढ रहे हैं। आप एक स्थानीय व्यक्ति से रास्ता पूछते हैं और दिशा समझने की कोशिश करते हैं।", lines: [{ who: "you", sq: "Më falni, ku është stacioni i autobusit?", hi: "माफ़ कीजिए, बस स्टेशन कहाँ है?" }, { who: "them", sq: "Është afër, rreth dhjetë minuta në këmbë.", hi: "यह पास है, पैदल लगभग दस मिनट।" }, { who: "you", sq: "Duhet të shkoj drejt?", hi: "क्या मुझे सीधे जाना चाहिए?" }, { who: "them", sq: "Po, shkoni drejt deri te semafori.", hi: "हाँ, ट्रैफ़िक लाइट तक सीधे जाइए।" }, { who: "you", sq: "Pastaj majtas apo djathtas?", hi: "फिर बाएँ या दाएँ?" }, { who: "them", sq: "Kthehuni majtas.", hi: "बाएँ मुड़िए।" }, { who: "you", sq: "A është në këtë rrugë?", hi: "क्या यह इसी सड़क पर है?" }, { who: "them", sq: "Po, pastaj do ta shihni në të djathtë.", hi: "हाँ, फिर आप इसे दाईं ओर देखेंगे।" }, { who: "you", sq: "Faleminderit, flas pak shqip.", hi: "धन्यवाद, मैं थोड़ी अल्बानियन बोलता/बोलती हूँ।" }, { who: "them", sq: "Shumë mirë, shqipja juaj është e mirë.", hi: "बहुत अच्छा, आपकी अल्बानियन अच्छी है।" }, { who: "you", sq: "Faleminderit shumë për ndihmën.", hi: "मदद के लिए बहुत धन्यवाद।" }, { who: "them", sq: "S’ka problem, udhëtim të mbarë.", hi: "कोई समस्या नहीं, शुभ यात्रा।" }] },
{ title: "बेरात के रेस्तरां में रात का खाना", scene: "आप बेरात के पुराने शहर में एक स्थानीय रेस्तरां में हैं। आप दो लोगों के लिए मेज़ चाहते हैं, शाकाहारी विकल्प पूछते हैं और अंत में बिल माँगते हैं।", lines: [{ who: "them", sq: "Mirëdita, sa persona jeni?", hi: "नमस्ते, आप कितने लोग हैं?" }, { who: "you", sq: "Jemi dy persona.", hi: "हम दो लोग हैं।" }, { who: "them", sq: "Ju lutem, uluni këtu.", hi: "कृपया यहाँ बैठिए।" }, { who: "you", sq: "Faleminderit, mund të kem menynë?", hi: "धन्यवाद, क्या मुझे मेन्यू मिल सकता है?" }, { who: "them", sq: "Sigurisht, ja menyja.", hi: "बिल्कुल, यह मेन्यू है।" }, { who: "you", sq: "A keni ushqim vegjetarian?", hi: "क्या आपके पास शाकाहारी खाना है?" }, { who: "them", sq: "Po, kemi perime, supë dhe byrek me djathë.", hi: "हाँ, हमारे पास सब्ज़ियाँ, सूप और चीज़ ब्यूरेक है।" }, { who: "you", sq: "Çfarë rekomandoni?", hi: "आप क्या सुझाते हैं?" }, { who: "them", sq: "Rekomandoj perimet dhe byrekun.", hi: "मैं सब्ज़ियाँ और ब्यूरेक सुझाता/सुझाती हूँ।" }, { who: "you", sq: "Mirë, dua këtë pjatë.", hi: "ठीक है, मुझे यह डिश चाहिए।" }, { who: "them", sq: "Patjetër.", hi: "ज़रूर।" }, { who: "you", sq: "Në fund, faturën, ju lutem.", hi: "अंत में, बिल, कृपया।" }] },
{ title: "बस टिकट खरीदना", scene: "आप तिराना के बस स्टेशन पर हैं और प्रिश्तिना के लिए टिकट खरीदना चाहते हैं। आपको समय, प्लेटफ़ॉर्म और यात्रा की अवधि जाननी है।", lines: [{ who: "them", sq: "Përshëndetje, ku doni të shkoni?", hi: "नमस्ते, आप कहाँ जाना चाहते हैं?" }, { who: "you", sq: "Dua një biletë për Prishtinë.", hi: "मुझे प्रिश्तिना के लिए एक टिकट चाहिए।" }, { who: "them", sq: "Për sot apo për nesër?", hi: "आज के लिए या कल के लिए?" }, { who: "you", sq: "Për sot, ju lutem.", hi: "आज के लिए, कृपया।" }, { who: "them", sq: "Autobusi niset në orën dy.", hi: "बस दो बजे निकलती है।" }, { who: "you", sq: "Nga cila platformë?", hi: "किस प्लेटफ़ॉर्म से?" }, { who: "them", sq: "Nga platforma pesë.", hi: "प्लेटफ़ॉर्म पाँच से।" }, { who: "you", sq: "Sa zgjat udhëtimi?", hi: "यात्रा कितनी देर की है?" }, { who: "them", sq: "Rreth katër orë.", hi: "लगभग चार घंटे।" }, { who: "you", sq: "A mund të paguaj me kartë?", hi: "क्या मैं कार्ड से भुगतान कर सकता/सकती हूँ?" }, { who: "them", sq: "Po, mundeni.", hi: "हाँ, कर सकते हैं।" }, { who: "you", sq: "Faleminderit shumë.", hi: "बहुत धन्यवाद।" }] },
{ title: "बाज़ार में स्मृति-चिह्न खरीदना", scene: "आप क्रूजा के पुराने बाज़ार में हैं। आप एक छोटा स्मृति-चिह्न खरीदना चाहते हैं, दाम पूछते हैं और कार्ड से भुगतान करना चाहते हैं।", lines: [{ who: "them", sq: "Mirëdita, çfarë kërkoni?", hi: "नमस्ते, आप क्या ढूँढ रहे हैं?" }, { who: "you", sq: "Po kërkoj një suvenir.", hi: "मैं एक स्मृति-चिह्न ढूँढ रहा/रही हूँ।" }, { who: "them", sq: "Kemi këto punime tradicionale.", hi: "हमारे पास ये पारंपरिक हस्तशिल्प हैं।" }, { who: "you", sq: "Më pëlqen kjo ngjyrë.", hi: "मुझे यह रंग पसंद है।" }, { who: "them", sq: "Është shumë e bukur.", hi: "यह बहुत सुंदर है।" }, { who: "you", sq: "Sa kushton kjo?", hi: "इसकी कीमत कितनी है?" }, { who: "them", sq: "Kushton dhjetë euro.", hi: "इसकी कीमत दस यूरो है।" }, { who: "you", sq: "A keni çmim më të lirë?", hi: "क्या आपके पास सस्ता दाम है?" }, { who: "them", sq: "Për ju, tetë euro.", hi: "आपके लिए आठ यूरो।" }, { who: "you", sq: "Mirë, do ta marr.", hi: "ठीक है, मैं इसे ले लूँगा/लूँगी।" }, { who: "them", sq: "Para apo kartë?", hi: "नकद या कार्ड?" }, { who: "you", sq: "Me kartë, ju lutem.", hi: "कार्ड से, कृपया।" }] },
{ title: "फार्मेसी में दवा लेना", scene: "आप सारांदा में हैं और आपको सिरदर्द है। आप फार्मेसी में जाकर दवा, खुराक और पर्ची के बारे में पूछते हैं।", lines: [{ who: "them", sq: "Përshëndetje, si mund t’ju ndihmoj?", hi: "नमस्ते, मैं आपकी कैसे मदद कर सकता/सकती हूँ?" }, { who: "you", sq: "Kam dhimbje koke.", hi: "मेरे सिर में दर्द है।" }, { who: "them", sq: "Sa kohë keni dhimbje?", hi: "आपको कितनी देर से दर्द है?" }, { who: "you", sq: "Që nga mëngjesi.", hi: "सुबह से।" }, { who: "them", sq: "A keni temperaturë?", hi: "क्या आपको बुखार है?" }, { who: "you", sq: "Jo, nuk kam temperaturë.", hi: "नहीं, मुझे बुखार नहीं है।" }, { who: "them", sq: "Ky ilaç mund të ndihmojë.", hi: "यह दवा मदद कर सकती है।" }, { who: "you", sq: "A duhet recetë?", hi: "क्या पर्ची चाहिए?" }, { who: "them", sq: "Jo, nuk duhet recetë.", hi: "नहीं, पर्ची नहीं चाहिए।" }, { who: "you", sq: "Sa herë në ditë?", hi: "दिन में कितनी बार?" }, { who: "them", sq: "Dy herë në ditë, me ujë.", hi: "दिन में दो बार, पानी के साथ।" }, { who: "you", sq: "Faleminderit.", hi: "धन्यवाद।" }] },
{ title: "स्थानीय व्यक्ति से हल्की बातचीत", scene: "आप प्रिज़रेन के एक छोटे कैफ़े में बैठे हैं। पास बैठा स्थानीय व्यक्ति आपसे बातचीत शुरू करता है और आप अपनी यात्रा, भाषा और शहर के बारे में बात करते हैं।", lines: [{ who: "you", sq: "Përshëndetje, a është ky vend i lirë?", hi: "नमस्ते, क्या यह जगह खाली है?" }, { who: "them", sq: "Po, uluni, ju lutem.", hi: "हाँ, बैठिए, कृपया।" }, { who: "you", sq: "Faleminderit, qyteti është shumë i bukur.", hi: "धन्यवाद, शहर बहुत सुंदर है।" }, { who: "them", sq: "Faleminderit, nga jeni?", hi: "धन्यवाद, आप कहाँ से हैं?" }, { who: "you", sq: "Jam nga India.", hi: "मैं भारत से हूँ।" }, { who: "them", sq: "A jeni këtu për pushime?", hi: "क्या आप यहाँ छुट्टियों पर हैं?" }, { who: "you", sq: "Po, jam për pushime dhe flas pak shqip.", hi: "हाँ, मैं छुट्टियों पर हूँ और थोड़ी अल्बानियन बोलता/बोलती हूँ।" }, { who: "them", sq: "Shumë mirë, shqipja juaj është e mirë.", hi: "बहुत अच्छा, आपकी अल्बानियन अच्छी है।" }, { who: "you", sq: "Më pëlqen ushqimi këtu.", hi: "मुझे यहाँ का खाना पसंद है।" }, { who: "them", sq: "Duhet të provoni byrekun lokal.", hi: "आपको स्थानीय ब्यूरेक ज़रूर चखना चाहिए।" }, { who: "you", sq: "Patjetër, faleminderit për këshillën.", hi: "ज़रूर, सलाह के लिए धन्यवाद।" }, { who: "them", sq: "Mirë se vini dhe udhëtim të mbarë.", hi: "आपका स्वागत है और शुभ यात्रा।" }] }
];
